1	 import { create } from 'zustand';
2	 
3	 interface CartItem {
4	   id: number;
5	   name: string;
6	   price: number;
7	   quantity: number;
8	 }
9	 
10	 interface CartState {
11	   items: CartItem[];
12	   total: number;
13	   addItem: (item: CartItem) => void;
14	   updateQuantity: (id: number, quantity: number) => void;
15	   removeItem: (id: number) => void;
16	 }
17	 
18	 export const useCartStore = create<CartState>((set, get) => ({
19	   items: [],
20	   total: 0,
21	   addItem: (item) => {
22	     set((state) => ({
23	       items: [...state.items, item],
24	       total: state.items.reduce((sum, i) => sum + i.price * i.quantity, 0) + item.price * item.quantity
25	     }));
26	   },
27	   updateQuantity: (id, quantity) => {
28	     const items = get().items;
29	     const item = items.find(i => i.id === id);
30	     if (item) {
31	       item.quantity = quantity;
32	       set({ items });
33	     }
34	   },
35	   removeItem: (id) => {
36	     set((state) => {
37	       const items = state.items.filter(i => i.id !== id);
38	       return { items, total: items.reduce((sum, i) => sum + i.price * i.quantity, 0) };
39	     });
40	   }
41	 }));

