updateQuantity: (id, quantity) => {
  set((state) => {
    const items = state.items.map(i =>
      i.id === id ? { ...i, quantity } : i
    );
    return {
      items,
      total: items.reduce((sum, i) => sum + i.price * i.quantity, 0)
    };
  });
},
